function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

const baseConfig = getNodeJson('SetMixed - Configuracion efectiva');
const triggerConfig = getNodeJson('SetTrigger - Flujo');
const mergedFlags = { ...(baseConfig.flags || {}) };
function mergeFlag(name) {
  const value = triggerConfig[name];
  if (value === undefined || value === null || value === '') return;
  if (typeof value === 'boolean') mergedFlags[name] = value;
  else if (typeof value === 'number') mergedFlags[name] = value !== 0;
  else {
    const text = String(value).trim().toLowerCase();
    if (['true','1','yes','y','si','s','on','enabled'].includes(text)) mergedFlags[name] = true;
    else if (['false','0','no','n','off','disabled'].includes(text)) mergedFlags[name] = false;
  }
}
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) mergeFlag(key);
const config = { ...baseConfig, ...triggerConfig, flags: mergedFlags };
for (const [key, value] of Object.entries(mergedFlags)) config[key] = value;
const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();
const timezone = String(config.timezone || 'America/Santiago').trim();
const reportMode = String(config.report_mode || '').trim();
const warrantyDays = Number(config.warranty_warning_days || 90);
const now = new Date();

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) {
        rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      }
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}

function scalarText(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = String(value).trim();
    return text === '[object Object]' ? '' : text;
  }
  return '';
}

function cleanContactText(value) {
  let text = scalarText(value);
  if (!text) return '';
  if (text.includes(' / ')) text = text.split(' / ')[0].trim();
  return text;
}

function normalizeContactEntry(entry) {
  if (entry === undefined || entry === null) return '';
  const direct = cleanContactText(entry);
  if (direct) return direct;
  if (Array.isArray(entry)) return entry.map(normalizeContactEntry).filter(Boolean).join(', ');
  if (typeof entry === 'object') {
    if (entry.fields && typeof entry.fields === 'object') {
      const fromFields = normalizeContactEntry(entry.fields);
      if (fromFields) return fromFields;
    }
    if (entry.objects && typeof entry.objects === 'object') {
      return Object.values(entry.objects).map(normalizeContactEntry).filter(Boolean).join(', ');
    }
    const preferred = ['contact_id_friendlyname','person_id_friendlyname','user_id_friendlyname','contact_name','person_name','display_name','name','friendlyname','email','email_address'];
    for (const field of preferred) {
      const text = cleanContactText(entry[field]);
      if (text) return text;
    }
    const nested = ['contact_id','person_id','user_id','contact','person','user'];
    for (const field of nested) {
      const text = normalizeContactEntry(entry[field]);
      if (text) return text;
    }
  }
  return '';
}

function normalizeContacts(value) {
  const text = normalizeContactEntry(value);
  if (!text) return '';
  const unique = [];
  const seen = new Set();
  for (const part of text.split(',').map(v => cleanContactText(v)).filter(Boolean)) {
    const key = part.toLowerCase();
    if (!seen.has(key)) { seen.add(key); unique.push(part); }
  }
  return unique.join(', ');
}

function isBlankValue(value) {
  const v = String(value ?? '').trim();
  return !v || v === '-' || v.toLowerCase() === 'n/a' || v.toLowerCase() === 'null' || v.toLowerCase() === 'undefined';
}

function inferWorkstationClass(f = {}) {
  // No se realiza separaci\u00f3n PC vs Laptop en este flujo.
  // Todo activo cuya clase base corresponda a PC/Laptop, PC o Laptop se consolida como PC/Laptop.
  return 'PC/Laptop';
}

function normalizeClass(value, f = {}) {
  const raw = String(value || '-').trim();
  const lower = raw.toLowerCase();

  if (
    lower === 'pc' ||
    lower === 'laptop' ||
    lower === 'pc/laptop' ||
    lower.includes('pc/laptop') ||
    lower.includes('desktop') ||
    lower.includes('laptop') ||
    lower.includes('notebook') ||
    lower.includes('portable') ||
    lower.includes('computer')
  ) {
    return 'PC/Laptop';
  }

  if (
    lower === 'mobilephone' ||
    lower.includes('mobilephone') ||
    lower.includes('mobile phone') ||
    lower.includes('smartphone') ||
    lower.includes('phone') ||
    lower.includes('telefono') ||
    lower.includes('tel\u00e9fono') ||
    lower.includes('celular')
  ) return 'Tel\u00e9fonos m\u00f3viles';

  if (lower === 'tablet' || lower.includes('tablet')) return 'Tablet';
  if (lower === 'printer' || lower.includes('impresora') || lower.includes('printer')) return 'Impresoras';
  if (lower === 'peripheral' || lower.includes('periferico') || lower.includes('perif\u00e9rico') || lower.includes('peripheral')) return 'Perif\u00e9ricos';

  return 'Perif\u00e9ricos';
}

function classSortWeight(className) {
  const order = {
    'PC/Laptop': 10,
    'Tablet': 20,
    'Tel\u00e9fonos m\u00f3viles': 30,
    'Impresoras': 40,
    'Perif\u00e9ricos': 50,
  };
  return order[className] || 80;
}

function translateStatus(value) {
  const map = {
    stock: 'En Stock',
    implementation: 'No Productivo',
    production: 'En Producci\u00f3n',
    obsolete: 'Obsoleto',
  };
  const key = String(value || '').trim().toLowerCase();
  return map[key] || String(value || '-');
}

function parseDate(value) {
  const text = String(value || '').trim();
  if (!text || text === '-') return null;
  const normalized = text.replace(' ', 'T');
  const date = new Date(normalized);
  return Number.isNaN(date.getTime()) ? null : date;
}

function formatDate(dateValue) {
  if (!dateValue) return '-';
  const date = dateValue instanceof Date ? dateValue : parseDate(dateValue);
  if (!date) return '-';
  return date.toLocaleDateString('es-CL', { timeZone: timezone, year:'numeric', month:'2-digit', day:'2-digit' });
}

function daysBetween(fromDate, toDate) {
  const ms = 24 * 60 * 60 * 1000;
  return Math.ceil((toDate.getTime() - fromDate.getTime()) / ms);
}

function groupBy(list, fn) {
  const map = new Map();
  for (const item of list) {
    const key = fn(item) || '-';
    if (!map.has(key)) map.set(key, []);
    map.get(key).push(item);
  }
  return map;
}

function buildAssetRows(list, emptyText) {
  if (!list.length) {
    return `<tr><td colspan="7" style="padding:14px; font-size:12px; color:#64748b;">${escapeHtml(emptyText)}</td></tr>`;
  }
  return list.map(a => `
    <tr>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.finalclass)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;"><strong>${escapeHtml(a.name)}</strong></td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.location)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.brand)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.model)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.serial)}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(a.warrantyDateDisplay)}</td>
    </tr>`).join('');
}

function buildClassSummary(list) {
  const groups = [...groupBy(list, a => a.finalclass).entries()]
    .sort((a, b) => classSortWeight(a[0]) - classSortWeight(b[0]) || a[0].localeCompare(b[0], 'es'));
  if (!groups.length) return '<tr><td colspan="4" style="padding:12px; font-size:12px; color:#64748b;">Sin registros para el criterio del reporte.</td></tr>';
  return groups.map(([klass, rows]) => {
    const locations = new Set(rows.map(r => r.location).filter(v => !isBlankValue(v) && v !== 'Sin bodega/localidad')).size;
    const observation = locations
      ? `Distribuido en ${locations} ${locations === 1 ? 'bodega/localidad' : 'bodegas/localidades'}.`
      : 'Todos los registros requieren normalizaci\u00f3n de bodega/localidad.';
    return `<tr>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(klass)}</td>
      <td align="right" style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;"><strong>${rows.length}</strong></td>
      <td align="right" style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${locations}</td>
      <td style="padding:8px; border-top:1px solid #e5e7eb; font-size:12px;">${escapeHtml(observation)}</td>
    </tr>`;
  }).join('');
}

const rawRows = flattenInput($input.all());
let assets = rawRows.map(row => {
  const f = row.fields || row;
  const warrantyDate = parseDate(getField(f, ['end_of_warranty', 'warranty_end_date'], ''));
  const contacts = normalizeContacts(getField(f, ['contacts_list', 'contact_list', 'contact_id_friendlyname', 'contact_name'], ''));
  const statusRaw = String(getField(f, ['status'], '-')).trim().toLowerCase();
  const days = warrantyDate ? daysBetween(now, warrantyDate) : null;
  return {
    id: getField(f, ['id', 'key'], row.key || ''),
    name: getField(f, ['name', 'friendlyname'], '-'),
    finalclass: normalizeClass(getField(f, ['finalclass', 'class'], '-'), f),
    statusRaw,
    status: translateStatus(statusRaw),
    organization: getField(f, ['org_id_friendlyname', 'org_name', 'organization_name'], '-'),
    location: getField(f, ['location_id_friendlyname', 'location_name', 'location_id'], 'Sin bodega/localidad'),
    contact: contacts,
    brand: getField(f, ['brand_id_friendlyname', 'brand'], '-'),
    model: getField(f, ['model_id_friendlyname', 'model'], '-'),
    serial: getField(f, ['serialnumber', 'serial_number'], '-'),
    assetNumber: getField(f, ['asset_number', 'assetnumber'], '-'),
    purchaseDate: getField(f, ['purchase_date'], '-'),
    warrantyDate,
    warrantyDateDisplay: formatDate(warrantyDate),
    daysToWarranty: days,
    daysLabel: days === null ? '-' : (days >= 0 ? `${days} d\u00edas` : `${Math.abs(days)} d\u00edas vencida`),
  };
});

if (reportMode === 'without_contact_production') {
  assets = assets.filter(a => a.statusRaw === 'production' && isBlankValue(a.contact));
  assets.sort((a, b) => a.location.localeCompare(b.location, 'es') || classSortWeight(a.finalclass) - classSortWeight(b.finalclass) || a.name.localeCompare(b.name, 'es'));
} else if (reportMode === 'warranty_upcoming') {
  assets = assets.filter(a => a.statusRaw !== 'obsolete' && a.warrantyDate && a.daysToWarranty >= 0 && a.daysToWarranty <= warrantyDays);
  assets.sort((a, b) => a.daysToWarranty - b.daysToWarranty || a.name.localeCompare(b.name, 'es'));
} else if (reportMode === 'warranty_expired') {
  assets = assets.filter(a => a.statusRaw !== 'obsolete' && a.warrantyDate && a.daysToWarranty < 0);
  assets.sort((a, b) => a.daysToWarranty - b.daysToWarranty || a.name.localeCompare(b.name, 'es'));
}

const generatedAt = now.toLocaleString('es-CL', { timeZone: timezone, year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
function formatFileTimestamp(date) {
  const pad = (value) => String(value).padStart(2, '0');
  return `${date.getFullYear()}${pad(date.getMonth() + 1)}${pad(date.getDate())}_${pad(date.getHours())}${pad(date.getMinutes())}`;
}

function slugFilePart(value, fallback = 'reporte') {
  const slug = String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '');
  return (slug || fallback).slice(0, 48).replace(/_+$/g, '');
}

const generatedAtFile = formatFileTimestamp(now);
const subjectBase = String(config.email_subject || 'Reporte CMDB').trim();
const emailSubject = itopOrganization ? `${subjectBase} - ${itopOrganization}` : subjectBase;

const headers = ['Clase','Activo','Bodega','Marca','Modelo','Serie','Garant\u00eda'];
const csvContent = '\uFEFF' + [
  headers.map(csvEscape).join(';'),
  ...assets.map(a => [a.finalclass,a.name,a.location,a.brand,a.model,a.serial,a.warrantyDateDisplay].map(csvEscape).join(';'))
].join('\r\n');

const groupedByLocation = [...groupBy(assets, a => a.location).entries()]
  .sort((a, b) => a[0].localeCompare(b[0], 'es'));

let detailBlocks = '';
if (!assets.length) {
  detailBlocks = '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">No se encontraron activos para el criterio del reporte.</td></tr></table>';
} else {
  detailBlocks = groupedByLocation.map(([location, rows]) => `
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin:0 0 16px 0; border:1px solid #dbe3ec;">
      <tr>
        <td style="background-color:#f8fafc; padding:10px 12px; border-bottom:1px solid #dbe3ec;">
          <div style="font-size:14px; line-height:20px; font-weight:bold; color:#0f172a;">${escapeHtml(location)} <span style="color:#64748b; font-weight:normal;">(${rows.length} activos)</span></div>
          <div style="font-size:12px; line-height:18px; color:#64748b; margin-top:4px;">Agrupaci\u00f3n por bodega/localidad para facilitar revisi\u00f3n operacional.</div>
        </td>
      </tr>
      <tr><td>
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; width:100%;">
          <thead><tr style="background:#f8fafc;">
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Clase</th>
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Activo</th>
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Bodega</th>
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Marca</th>
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Modelo</th>
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Serie</th>
            <th align="left" style="padding:8px; font-size:11px; color:#475569;">Garant\u00eda</th>
          </tr></thead>
          <tbody>${buildAssetRows(rows, 'Sin registros.')}</tbody>
        </table>
      </td></tr>
    </table>`).join('');
}

const csvBaseName = slugFilePart(config.csv_basename || 'cmdb_reporte');
const csvFileName = `${csvBaseName}_${generatedAtFile}.csv`;
const withoutLocationCount = assets.filter(a => isBlankValue(a.location) || a.location === 'Sin bodega/localidad').length;
const expiredWarrantyCount = assets.filter(a => a.warrantyDate && a.daysToWarranty < 0).length;
const classTypeCount = new Set(assets.map(a => a.finalclass).filter(Boolean)).size;
const pcLaptopCount = assets.filter(a => a.finalclass === 'PC/Laptop').length;
const tabletCount = assets.filter(a => a.finalclass === 'Tablet').length;
const mobileCount = assets.filter(a => a.finalclass === 'Tel\u00e9fonos m\u00f3viles').length;
const printerCount = assets.filter(a => a.finalclass === 'Impresoras').length;
const peripheralCount = assets.filter(a => a.finalclass === 'Perif\u00e9ricos').length;

return [{
  json: {
    flags: config.flags || {},
    report_template_key: config.report_template_key,
    template_root: config.template_root,
    include_attachment: config.flags?.include_attachment ?? config.include_attachment,
    include_detail: config.flags?.include_detail ?? config.include_detail,
    include_summary: config.flags?.include_summary ?? config.include_summary,
    include_operational_notes: config.flags?.include_operational_notes ?? config.include_operational_notes,
    include_itop_button_footer: config.flags?.include_itop_button_footer ?? config.include_itop_button_footer,
    email_from: config.email_from,
    email_to: config.email_to,
    email_cc: config.email_cc || '',
    email_bcc: config.email_bcc || '',
    email_subject: emailSubject,
    company,
    Company: company,
    itop_organization: itopOrganization || '-',
    generated_at: generatedAt,
    total_assets: String(assets.length),
    production_count: String(assets.filter(a => a.statusRaw === 'production').length),
    without_contact_count: String(assets.filter(a => isBlankValue(a.contact)).length),
    without_location_count: String(withoutLocationCount),
    expired_warranty_count: String(expiredWarrantyCount),
    class_type_count: String(classTypeCount),
    pc_laptop_count: String(pcLaptopCount),
    tablet_count: String(tabletCount),
    mobile_count: String(mobileCount),
    printer_count: String(printerCount),
    peripheral_count: String(peripheralCount),
    warranty_days: String(warrantyDays),
    class_summary_rows: buildClassSummary(assets),
    detail_blocks: detailBlocks,
    report_title: config.report_title || subjectBase,
    report_description: config.report_description || '',
    operational_notes: config.operational_notes || '',
    itop_url: config.itop_url || '#',
    csv_filename: csvFileName,
    flags: config.flags || {},
  },
  binary: {
    csv: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileName: csvFileName,
    },
  },
}];

const fs = require('fs');
const path = require('path');

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function readText(filePath) {
  return fs.readFileSync(filePath, 'utf8');
}

function render(template, values) {
  return String(template || '').replace(/{{\s*([\w.]+)\s*}}/g, (_, key) => {
    const parts = key.split('.');
    let value = values;
    for (const part of parts) value = value?.[part];
    return value === undefined || value === null ? '' : String(value);
  });
}

function normalizeText(value, forSubject = false) {
  let text = String(value ?? '');
  const htmlMap = [
    ['Automatizaci??n','Automatizaci&oacute;n'], ['Organizaci??n','Organizaci&oacute;n'], ['organizaci??n','organizaci&oacute;n'],
    ['Producci??n','Producci&oacute;n'], ['garant??a','garant&iacute;a'], ['Garant??a','Garant&iacute;a'], ['GARANT??A','GARANT&Iacute;A'],
    ['pr??ximos','pr&oacute;ximos'], ['Pr??ximos','Pr&oacute;ximos'], ['PR??XIMOS','PR&Oacute;XIMOS'], ['pr??ximo','pr&oacute;ximo'], ['pr??xima','pr&oacute;xima'],
    ['d??as','d&iacute;as'], ['D??AS','D&Iacute;AS'], ['D??as','D&iacute;as'], ['m??s','m&aacute;s'], ['M??S','M&Aacute;S'], ['M??s','M&aacute;s'],
    ['T??tulo','T&iacute;tulo'], ['antig??edad','antig&uuml;edad'], ['actualizaci??n','actualizaci&oacute;n'], ['configuraci??n','configuraci&oacute;n'],
    ['f??sicos','f&iacute;sicos'], ['f??sico','f&iacute;sico'], ['f??sica','f&iacute;sica'], ['tel??fono','tel&eacute;fono'], ['m??viles','m&oacute;viles'],
    ['perif??rico','perif&eacute;rico'], ['perif??ricos','perif&eacute;ricos'], ['??nico','&uacute;nico'], ['??nica','&uacute;nica'], ['??ltimo','&uacute;ltimo'],
    ['cr??tico','cr&iacute;tico'], ['cr??ticos','cr&iacute;ticos'], ['par??metros','par&aacute;metros'], ['env??a','env&iacute;a'], ['envi??','envi&oacute;'],
    ['asignaci??n','asignaci&oacute;n'], ['ubicaci??n','ubicaci&oacute;n'], ['descripci??n','descripci&oacute;n'], ['categor??a','categor&iacute;a'],
    ['seg??n','seg&uacute;n'], ['hist??rico','hist&oacute;rico'], ['relaci??n','relaci&oacute;n'], ['operaci??n','operaci&oacute;n'], ['an??lisis','an&aacute;lisis'],
    ['creaci??n','creaci&oacute;n'], ['aprobaci??n','aprobaci&oacute;n'], ['atenci??n','atenci&oacute;n'], ['informaci??n','informaci&oacute;n'],
    ['clasificaci??n','clasificaci&oacute;n'], ['revisi??n','revisi&oacute;n'], ['intervenci??n','intervenci&oacute;n'], ['secci??n','secci&oacute;n'],
    ['l??nea','l&iacute;nea'], ['c??digos','c&oacute;digos'], ['d??nde','d&oacute;nde'], ['espa??ol','espa&ntilde;ol'], ['vi??etas','vi&ntilde;etas'],
    ['m??ltiples','m&uacute;ltiples'], ['m??xima','m&aacute;xima'], ['r??pida','r&aacute;pida'], ['reposici??n','reposici&oacute;n'],
    ['est??ndar','est&aacute;ndar'], ['alg??n','alg&uacute;n'], ['??til','&uacute;til'], ['port??til','port&aacute;til']
  ];
  const subjectMap = htmlMap.map(([bad, good]) => [bad, good
    .replace(/&aacute;/g,'a').replace(/&eacute;/g,'e').replace(/&iacute;/g,'i').replace(/&oacute;/g,'o').replace(/&uacute;/g,'u')
    .replace(/&Aacute;/g,'A').replace(/&Eacute;/g,'E').replace(/&Iacute;/g,'I').replace(/&Oacute;/g,'O').replace(/&Uacute;/g,'U')
    .replace(/&uuml;/g,'u').replace(/&Uuml;/g,'U').replace(/&ntilde;/g,'n').replace(/&Ntilde;/g,'N')]);
  for (const [bad, good] of (forSubject ? subjectMap : htmlMap)) text = text.split(bad).join(good);
  text = text.split(' ?? ').join(forSubject ? ' - ' : ' &bull; ');
  text = text.split('??').join(forSubject ? '-' : '&bull;');
  return text;
}

function getNodeJson(name) {
  try { return $(name).first()?.json || {}; } catch (error) { return {}; }
}

function normalizeBoolean(value, fallback = true) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si', 's', 'on', 'enabled'].includes(text)) return true;
  if (['false', '0', 'no', 'n', 'off', 'disabled'].includes(text)) return false;
  return fallback;
}

function flagEnabled(data, name, fallback = true) {
  const trigger = getNodeJson('SetTrigger - Flujo');
  const mixed = getNodeJson('SetMixed - Configuracion efectiva');
  const value = trigger[name] ?? trigger.flags?.[name] ?? data[name] ?? data.flags?.[name] ?? mixed[name] ?? mixed.flags?.[name];
  return normalizeBoolean(value, fallback);
}

function notesList(value) {
  const lines = String(value ?? '')
    .split(/\r?\n|\. /)
    .map(v => v.trim().replace(/\.$/, ''))
    .filter(Boolean);
  if (!lines.length) return '<div style="font-size:13px; line-height:20px; color:#64748b;">Sin observaciones adicionales.</div>';
  return '<ul style="margin:0; padding-left:18px; color:#374151; font-size:13px; line-height:20px;">' +
    lines.map(line => '<li>' + escapeHtml(line) + '.</li>').join('') +
    '</ul>';
}

function statCard(data, stat) {
  const value = data[stat.value] ?? data[stat.fallbackValue] ?? '-';
  return '<td class="summary-card" width="33.33%" valign="top"><table role="presentation" width="100%" style="border:1px solid ' + stat.border + '; background-color:' + stat.background + ';"><tr><td style="padding:12px;"><div style="font-size:11px; color:' + stat.labelColor + '; font-weight:bold;">' + escapeHtml(stat.label) + '</div><div style="font-size:24px; color:' + stat.valueColor + '; font-weight:bold;">' + escapeHtml(value) + '</div></td></tr></table></td>';
}

function statRows(data, stats) {
  const rows = [];
  for (let i = 0; i < stats.length; i += 3) {
    const cells = stats.slice(i, i + 3).map(stat => statCard(data, stat));
    while (cells.length < 3) cells.push('<td class="summary-card" width="33.33%" valign="top">&nbsp;</td>');
    rows.push('<tr>' + cells.join('') + '</tr>');
  }
  return rows.join('\n');
}

function simpleTable(title, rows, headers, emptyText) {
  if (!rows) return '';
  const headerHtml = headers.map(h => '<th align="left" style="padding:8px; font-size:11px; color:#475569;">' + escapeHtml(h) + '</th>').join('');
  const body = rows || '<tr><td colspan="' + headers.length + '" style="padding:14px; font-size:12px; color:#64748b;">' + escapeHtml(emptyText || 'Sin registros.') + '</td></tr>';
  return '<div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">' + escapeHtml(title) + '</div><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; border:1px solid #dbe3ec;"><thead><tr style="background:#f8fafc;">' + headerHtml + '</tr></thead><tbody>' + body + '</tbody></table>';
}

function tableContent(data) {
  const blocks = [];
  if (data.detail_blocks) blocks.push(data.detail_blocks);
  if (data.class_asset_blocks) blocks.push(data.class_asset_blocks);
  if (data.status_asset_blocks) blocks.push(data.status_asset_blocks);
  if (data.review_asset_blocks) blocks.push(data.review_asset_blocks);
  if (data.ticket_sections) blocks.push(data.ticket_sections);
  if (data.older_section) blocks.push(data.older_section);
  if (data.recent_section) blocks.push(data.recent_section);
  if (data.ticket_rows_html) blocks.push(simpleTable('Tickets abiertos', data.ticket_rows_html, ['Criticidad','Referencia','Tipo','Titulo','Solicitante','Estado','Creacion','Ultimo update','Antiguedad','SLA'], 'Sin tickets.'));
  if (data.movement_rows) blocks.push(simpleTable('Movimientos recientes', data.movement_rows, ['Fecha','Movimiento','Activo','Clase','Origen','Destino'], 'Sin movimientos.'));
  if (data.class_summary_rows) blocks.push(simpleTable('Resumen por clase', data.class_summary_rows, ['Clase','Total','Dato 1','Observacion'], 'Sin resumen por clase.'));
  if (data.warehouse_summary_rows) blocks.push(simpleTable('Resumen por bodega/localidad', data.warehouse_summary_rows, ['Bodega/localidad','Total','Clases','Observacion'], 'Sin resumen por bodega.'));
  if (data.status_summary_rows) blocks.push(simpleTable('Resumen por estado', data.status_summary_rows, ['Estado','Total','Dato 1','Observacion'], 'Sin resumen por estado.'));
  if (data.location_summary_rows) blocks.push(simpleTable('Resumen por localidad', data.location_summary_rows, ['Localidad','Total','Dato 1','Observacion'], 'Sin resumen por localidad.'));
  if (data.class_status_rows) blocks.push(simpleTable('Clase por estado', data.class_status_rows, ['Clase','Productivo','Inventario','No operativo'], 'Sin matriz de estados.'));
  if (data.location_matrix_rows) {
    const header = data.location_matrix_header_cells || '<th align="left" style="padding:8px; font-size:11px; color:#475569;">Bodega/localidad</th>';
    blocks.push('<div style="font-size:14px; font-weight:bold; color:#1e293b; margin:18px 0 8px 0;">Matriz por bodega/localidad</div><table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border-collapse:collapse; border:1px solid #dbe3ec;"><thead><tr style="background:#f8fafc;">' + header + '</tr></thead><tbody>' + data.location_matrix_rows + '</tbody></table>');
  }
  if (data.top_location_rows) blocks.push(simpleTable('Top bodega/localidad', data.top_location_rows, ['Bodega/localidad','Total','Dato 1','Observacion'], 'Sin top de localidades.'));
  return blocks.filter(Boolean).join('\n');
}

function buildHtml(item) {
  const data = item.json || {};
  const triggerConfig = getNodeJson('SetTrigger - Flujo');
  const mixedConfig = getNodeJson('SetMixed - Configuracion efectiva');
  const root = data.template_root || mixedConfig.template_root || triggerConfig.template_root || '/opt/n8n-config/templates/mail/v1';
  const key = data.report_template_key || mixedConfig.report_template_key || triggerConfig.report_template_key || 'cmdb-activos-sin-contacto';
  const contract = JSON.parse(readText(path.join(root, 'reports', key + '.json')));
  const partial = (name) => readText(path.join(root, contract.partials[name]));

  const styles = partial('styles');
  const header = render(partial('header'), {
    eyebrow: escapeHtml(contract.header?.eyebrow || 'Automatizacion ITSM / CMDB'),
    title: escapeHtml(data.report_title || data.email_subject || 'Reporte'),
    subtitle: escapeHtml(contract.header?.subtitle || ''),
    itop_organization: escapeHtml(data.itop_organization || '-'),
    generated_at: escapeHtml(data.generated_at || '-'),
    source_label: escapeHtml(data.source_label || data.report_source_label || contract.header?.source_label || '-'),
  });
  const summary = render(partial('summary'), { description: escapeHtml(data.report_description || contract.summary?.description || '') });
  const stats = render(partial('stats'), { stats_rows: statRows(data, contract.stats || []) });
  const criteria = render(partial('criteria'), contract.criteria || {});
  const tables = flagEnabled(data, 'include_detail', true) ? render(partial('tables'), {
    title: contract.tables?.title || 'Detalle operacional',
    subtitle: contract.tables?.subtitle || '',
    content: tableContent(data) || '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="border:1px solid #dbe3ec;"><tr><td style="padding:14px; font-size:13px; color:#64748b;">Sin registros para el criterio del reporte.</td></tr></table>',
  }) : '';
  const notes = flagEnabled(data, 'include_operational_notes', true) ? render(partial('notes'), { notes_list: notesList(data.operational_notes) }) : '';
  const cta = flagEnabled(data, 'include_itop_button_footer', true) ? render(partial('cta'), {
    href: escapeHtml(data.itop_url || '#'),
    label: contract.cta?.label || 'Abrir',
  }) : '';
  const footer = render(partial('footer'), {
    brand: contract.footer?.brand || 'Automatizacion ITSM / CMDB',
    company: escapeHtml(data.company || data.Company || ''),
    generated_at: escapeHtml(data.generated_at || '-'),
  });

  let html = render(partial('layout'), {
    title: escapeHtml(data.report_title || data.email_subject || 'Reporte'),
    styles,
    header,
    summary: flagEnabled(data, 'include_summary', true) ? summary : '',
    stats: flagEnabled(data, 'include_summary', true) ? stats : '',
    criteria,
    tables,
    notes,
    cta,
    footer,
  });
  html = normalizeText(html, false);
  data.email_subject = normalizeText(data.email_subject, true);

  const includeAttachment = flagEnabled(data, 'include_attachment', true);
  const binary = includeAttachment ? (item.binary || {}) : {};
  return {
    json: {
      ...data,
      html,
      template_version: contract.template_version || 'mail-v1',
      template_contract: key,
      include_attachment_effective: includeAttachment,
      attachment_binary_names: includeAttachment && binary.csv ? 'csv' : '',
      has_csv_binary: Boolean(binary.csv),
    },
    binary,
  };
}

return $input.all().map(buildHtml);

const base = $input.first()?.json || {};
const trigger = $('SetTrigger - Flujo').first()?.json || {};

function normalizeBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'y', 'si'].includes(text)) return true;
  if (['false', '0', 'no', 'n'].includes(text)) return false;
  return fallback;
}

const flags = { ...(base.flags || {}) };
for (const key of ['include_attachment', 'include_detail', 'include_summary', 'include_operational_notes', 'include_itop_button_footer', 'send_email']) {
  if (trigger[key] !== undefined && trigger[key] !== null && trigger[key] !== '') {
    flags[key] = normalizeBoolean(trigger[key], flags[key]);
  }
}

const setMixed = {
  ...base,
  ...trigger,
  flags,
  config_source: 'SetBase + SetTrigger',
};

return [{ json: setMixed }];

const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) {
  return String(body[name] ?? '').trim();
}

function positiveNumber(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return false;
  const n = Number(raw);
  return Number.isFinite(n) && n > 0;
}

function validDateText(name) {
  const value = text(name);
  if (!value) return false;
  const parsed = new Date(value.replace(' ', 'T'));
  return !Number.isNaN(parsed.getTime());
}

function dateWindowState() {
  const hasStart = text('start_date').length > 0;
  const hasEnd = text('end_date').length > 0;
  if (!hasStart && !hasEnd) return { provided: false, valid: false };
  if (!hasStart || !hasEnd) return { provided: true, valid: false, error: 'start_date y end_date deben enviarse juntos.' };
  if (!validDateText('start_date') || !validDateText('end_date')) return { provided: true, valid: false, error: 'start_date y end_date deben ser fechas v\u00e1lidas.' };
  const start = new Date(text('start_date').replace(' ', 'T'));
  const end = new Date(text('end_date').replace(' ', 'T'));
  if (start > end) return { provided: true, valid: false, error: 'start_date no puede ser mayor que end_date.' };
  return { provided: true, valid: true };
}

if (!text('email_to')) {
  errors.push('email_to es obligatorio para llamadas webhook.');
}

const webhookPath = 'cmdb-activos-sin-contacto';
const window = dateWindowState();

if (webhookPath === 'cmdb-movimientos-recientes-inventario') {
  const hasMovementDays = positiveNumber('movement_days');
  if (!hasMovementDays && !window.valid) {
    errors.push(window.error || 'Debe enviar movement_days positivo o la ventana start_date + end_date.');
  }
}

if (webhookPath === 'cmdb-activos-proximos-vencer-garantia') {
  if (!positiveNumber('warranty_warning_months')) {
    errors.push('warranty_warning_months es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (webhookPath === 'itsm-tickets-sin-actualizacion-24h') {
  if (!positiveNumber('stale_threshold_hours')) {
    errors.push('stale_threshold_hours es obligatorio y debe ser un numero mayor a 0.');
  }
}

if (window.provided && !window.valid && webhookPath !== 'cmdb-movimientos-recientes-inventario') {
  errors.push(window.error || 'Ventana de fechas inv\u00e1lida.');
}

const valid = errors.length === 0;

return [{
  json: {
    ...(item.json || {}),
    webhook_contract: {
      valid,
      status_code: valid ? 202 : 400,
      message: valid ? 'Workflow accepted' : errors.join(' '),
      errors,
    },
  },
  binary: item.binary,
}];

const item = $input.first();
const json = item?.json || {};

if (!json.webhook_contract?.valid) {
  return [];
}

const { webhook_contract, ...cleanJson } = json;
return [{ json: cleanJson, binary: item.binary }];
